var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"구마회 본부가 악마의 습격을 받았다는 연락을 받았습니다만…","JPN":"祓魔会の本部が悪魔に襲撃されたという連絡を受けましたが……","ENG":"We just received a message that the headquarters of Exorcism Council was attacked by a devil...","TWN":"我收到了驅魔會總部遭到魔鬼襲擊的消息…"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_05"},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"단 한 명의 사상자도 나오지 않았다는 건 예상 밖이군요.","JPN":"死傷者が一人も出なかったのは予想外ですね。","ENG":"But it's unexpected that there was not a single casualty.","TWN":"沒有出現任何傷亡，真是出乎意料。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"그 악마가 노리는 건 저희 목숨이 아니었습니다.","JPN":"あの悪魔が狙っていたのは、私たちの命ではなかったのです。","ENG":"I believe that devil was not after our lives.","TWN":"那個魔鬼的目標似乎並不是我們的性命。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"저를 찾아와서, 마르가리타 계시에 대해서 묻더군요.","JPN":"私を訪ね、マルガリータ啓示について尋ねました。","ENG":"She came to me and asked about the Revelation of Margarita.","TWN":"它來找我，詢問了關於瑪格麗特啟示的事情。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"계시라고요?","JPN":"啓示？","ENG":"Revelation?","TWN":"啟示嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그래서… 진실로 답을 하셨나요?","JPN":"それで……答えたのですか？","ENG":"So... did you answer truthfully?","TWN":"所以…你如實回答了嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"모르겠습니다.","JPN":"わかりません。","ENG":"I do not know.","TWN":"我不知道。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"포도향을 맡았다고 생각한 순간부터… 아무것도 기억이 나질 않더군요.","JPN":"ブドウの香りがしたと思った瞬間……記憶が途絶えたのです。","ENG":"The moment I thought I smelled grapes... I cannot recall any memories.","TWN":"從聞到葡萄香氣的那一刻起…我就什麼都不記得了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"포도향이라…","JPN":"ブドウの香り……","ENG":"Grapes...?","TWN":"葡萄香氣嗎…"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그러고보니 습격 현장에 쓰러져 있던 직원들도 그런 일관된 증언을 했었죠.","JPN":"そういえば、襲撃の現場に倒れていた職員たちも同じ証言をしていました。","ENG":"Come to think of it, the ones who were also ambushed on the scene seem to say the same thing.","TWN":"說起來，倒在襲擊現場的員工們也有類似的證詞。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"저희가 쫓던 녀석들 중에도 비슷한 특징을 가진 악마가 있습니다.","JPN":"私たちが追いかけていたやつらの中にも、似た特徴を持つ悪魔がいます。","ENG":"Among the devils we were pursuing, there was one with similar characteristics.","TWN":"我們追蹤的目標中也有類似特徵的魔鬼。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"단서를 모으고 있고, 조만간 놈의 꼬리를 잡을 수 있을 겁니다.","JPN":"手がかりを集めていますので、もうすぐやつの尻尾を掴めるはずです。","ENG":"We are currently gathering clues, and we will soon have the devil in custody.","TWN":"現在正在收集線索，很快就能抓住它的尾巴了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"악마를 찾아내는 일은 구마회의 소관이니, 그 일은 믿고 맡기겠습니다.","JPN":"悪魔を探し出すことは祓魔会の仕事ですから、この件はお任せしましょう。","ENG":"It is the duty of the Exorcism Council to find devils, so I shall entrust you with that task.","TWN":"尋找魔鬼是驅魔會的職責，這件事就交給你們了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만, 마르가리타 계시는 현세의 악에 맞설 성인을 찾기 위한 기밀 프로젝트 중 하나.","JPN":"ですが、マルガリータ啓示は現世の悪に立ち向かう聖人を探すための機密プロジェクトの一つ。","ENG":"However, the Revelation of Margarita is one of the secret projects to find a Saint who will stand against the evils of this world.","TWN":"但是，瑪格麗特啟示是為了尋找對抗現世之惡的聖人，而進行的機密項目之一。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 추적법이 성황청의 교의에 부합하지 않는 신비주의적 방식이기에 철저한 비밀리에 취급되고 있었을 텐데…","JPN":"その追跡方法は聖皇庁の教義に適合しない神秘主義的な方法ですので、徹底した管理のもと扱われていたはずですが……","ENG":"Its tracking method is mystical, and nonconforming to Holy Curia's doctrine, so it was kept in complete secret...","TWN":"由於不符合聖皇廳的教義，是以神秘主義的方式進行的，所以一直被嚴格保密…"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"일개 악마가 어떤 경위로 계시를 알고 있었는지 의문이 남는군요.","JPN":"一介の悪魔がどういった経緯で啓示のことを知ったのか、疑問ですね。","ENG":"So the question remains as to how a mere devil knew about it.","TWN":"一個小小的魔鬼是怎麼知道啟示的，真是令人疑惑。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"의심하고 싶진 않지만, 성황청 내부에 악마의 협력자가 있을지도 모릅니다.","JPN":"疑いたくはないのですが、聖皇庁の内部に悪魔の協力者がいるのかもしれません。","ENG":"I do not wish to raise suspicion, but there may be a devil's collaborator within Holy Curia.","TWN":"雖然不想懷疑，但聖皇廳內部可能有魔鬼的同夥。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"모든 전말은 그 악마를 붙잡은 뒤에 알 수 있겠죠.","JPN":"すべての顛末はその悪魔を捕まえれば、わかるでしょう。","ENG":"Everything will be revealed once we catch that devil.","TWN":"所有真相等抓住那個魔鬼後就能知道了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"점장님.","JPN":"店長。","ENG":"Gremory?","TWN":"店長。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"저… 할 말이 있어요.","JPN":"あの……話があります。","ENG":"There's... something I'd like to say.","TWN":"我…有話想說。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"으음…","JPN":"うーん……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"나 오늘은 피곤한데. 다음에 하면 안 될까?","JPN":"アタシ、今日はちょっと疲れてるの。あとにしてくれないかしら。","ENG":"I'm a little tired today. Could we talk later?","TWN":"我今天很累。可以改天再說嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"저 오늘부로 바텐더 일 관두려고요.","JPN":"私、今日からバーテンダーの仕事やめます。","ENG":"I'm thinking of quitting my job as the bartender today.","TWN":"我想辭掉調酒師的工作。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머, 돈이 부족한 거야? 아니면 일이 너랑 안 맞았니?","JPN":"あら、お金が足りないの？　それとも、仕事が合わない？","ENG":"Oh. Was the pay unsatisfactory? Or do you think the job isn't right for you?","TWN":"喔？是錢不夠嗎？還是工作不適合你？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"아뇨. 급여는 지금도 충분해요. 점장님과 함께 일하면서 보람도 느꼈고요.","JPN":"いいえ。給料には満足しています。店長と一緒に働けて、やり甲斐もありました。","ENG":"No. The pay's been more than enough. And I feel rewarded working with you.","TWN":"不，工資很夠，和店長一起工作也很有成就感。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그럼 왜 떠나려는 건데애?","JPN":"なら、どうして辞めちゃうの？","ENG":"Then why are you quitting?","TWN":"那你為什麼要離開呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"내가 가게 술을 혼자 다 마셔서 그래? 아니면 내가 주사를 너무 많이 부린 거니?","JPN":"アタシが店のお酒を全部飲んじゃったから？　それとも、アタシの酒癖がひどいから？","ENG":"Is it because I drink all the bar's alcohol? Or do I act out too much when drunk?","TWN":"是因為我一個人喝光店裡的酒嗎？還是因為我喝醉後鬧得太厲害？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"그, 그것도 전혀 해당이 안된다곤 못하겠지만…","JPN":"そ、それもまったくないとは言えませんが……","ENG":"I'd be lying if those weren't a part of it, but...","TWN":"嗯，這些也不能完全說沒有關係…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"점장님도 아시잖아요! 이 동네는 대낮에도 총성이 들린다고요! 길 건너엔 버젓이 독극물을 파는 범죄조직도 있고요!","JPN":"店長もわかってるでしょう！　この街、昼間にも銃声が聞こえるんです！　道の向こうには堂々と薬物を売る犯罪組織もいますし！","ENG":"You know just as well as I do! You hear gunshots in broad daylight in this neighborhood! And there's even a criminal organization that brazenly sells poison right across the street!","TWN":"店長你也知道！這裡大白天都能聽到槍聲！對面街上還有公然販賣毒品的犯罪組織！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그건 나도 어쩔 수 없어.","JPN":"それはアタシにだってどうしようもできないわ。","ENG":"There's nothing I can do about that.","TWN":"那我也沒辦法。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"카르텔의 조직력은 이미 도시의 공권력이 감당할 수준을 넘어섰고, 녀석들을 쫓아내 봐야 더한 지저분한 녀석들이 새로 들어올 뿐이니까.","JPN":"カルテルの組織力はもう街の公権力じゃ手に負えないし、あいつらを追い出したところでもっと悪いやつが入ってくるだけだもの。","ENG":"The cartel has already surpassed the level that the city's authorities can handle, and getting rid of them will only attract more filthy criminals here.","TWN":"那個組織的力量已經超出城市公權力能夠應對的範圍，就算把他們趕走，也只會有更骯髒的傢伙進來。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"정부도 포기한 도시를 점장님이 신경 쓰실 필욘 없잖아요.","JPN":"政府が見放した街を店長が気にかける必要ないじゃないですか。","ENG":"That's not something you should worry about when the government has given up on this city, Gremory.","TWN":"連政府都放棄的城市，店長還在這裡堅持什麼！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"그냥 가게를 옮기세요. 어디로 가든 여기보단 장사가 더 잘될 걸요?","JPN":"店を移しましょうよ。どこに行ってもきっとここよりはマシです。","ENG":"Let's just move the bar elsewhere. I'm sure that, wherever we move to, business will be far better than here.","TWN":"乾脆把店搬走吧。不管搬到哪裡，生意都會比這裡好。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"이런 시궁창 같은 동네는 모모 같은 아이에게도 나쁜 영향만 줄 거라고요.","JPN":"こんな汚れた街、モモのような子どもにも良くありません。","ENG":"This gutter will only be a bad influence on children like Momo.","TWN":"這種像垃圾堆一樣的地方，對莫莫會有不好的影響。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후후, 나쁜 영향이라…","JPN":"ふふ、どうかしら……","ENG":"Haha, a bad influence...?","TWN":"呵呵，不好的影響嗎…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"이미 술집에서 애를 키우는 마당에, 나빠진다고 얼마나 더 나빠지겠어?","JPN":"酒場で育てられた子よ？　今更でしょう。","ENG":"We're raising a child in this bar, so how much worse can it get?","TWN":"在酒吧長大的孩子，還能有什麼不好的影響？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"하하… 그게 문제라는 걸 자각하고 계신 줄은 몰랐네요.","JPN":"はは……自覚はあったんですね。","ENG":"Haha... I didn't know you were aware of that issue.","TWN":"哈哈…沒想到店長也意識到這個問題。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"그래서, 가게를 옮기실 생각은 없는 건가요?","JPN":"それで、店を移す気はないんですか？","ENG":"So, you don't have plans to relocate?","TWN":"所以，店長沒有打算搬家嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"운명이라는 말. 혹시 기억하니?","JPN":"運命って言葉、覚えているかしら。","ENG":"Do you know what fate is?","TWN":"命運這個詞。你還記得嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"점장님께서 손님들 연애운을 봐줄 때 자주 쓰시던 표현이죠.","JPN":"店長がお客さんたちの恋愛を占う時、よく使っていた表現ですね。","ENG":"It's a phrase you say to customers when you do relationship fortune telling.","TWN":"是店長在給客人看戀愛運勢時經常用的表述吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"운명은 항상 정해진 길로 흘러가기 때문에… 스스로 찾아 나서야 할 때도 있고, 서로 엇갈리지 않게 기다려야 할 때도 있는 법이라고요.","JPN":"運命はいつも決められた道に進むから……自分で探しに出ることも、お互いすれ違わないよう待つことも必要だって。","ENG":"Fate always follows a certain path... So, sometimes, one must go look for it oneself, and in other times, wait patiently to not miss one's chance.","TWN":"因為命運總是沿著既定的道路流轉…有時需要自己去尋找，有時則需要等待，避免錯過彼此。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그래, 맞아.","JPN":"そう、そのとおりよ。","ENG":"Yes, you’re correct.","TWN":"是的，沒錯。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그래서 기다리고 있는 거야. 나도, 임금님도.","JPN":"だから待っているの。アタシも、王様も。","ENG":"That's what I'm doing. Waiting. Me and little majesty both.","TWN":"所以我和國王在等待。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"이곳에서, 그 운명이 엇갈리지 않도록.","JPN":"ここで、その運命がすれ違わないように。","ENG":"We are waiting here, so that we don't miss our fate.","TWN":"在這裡，避免錯過命中註定的彼此。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"대체… 누굴 기다리고 계신 건데요?","JPN":"いったい……誰を待っているんですか？","ENG":"Who... are you waiting for?","TWN":"所以…到底在等誰？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"옛 고향의 벗.","JPN":"昔、故郷にいた友人よ。","ENG":"An old hometown friend.","TWN":"一個老朋友。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그땐 술을 참 못 마셨는데. 요즘은 좀 나아졌으려나 모르겠네.","JPN":"あの時はゲコだったけど、少しは飲めるようになったのかしら。","ENG":"She couldn't drink back then, but I wonder if she's able to now.","TWN":"那時真是不會喝酒，希望現在的她會好一些。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"으음…","JPN":"うーん……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"우리 임금님, 낮잠은 잘 잤어?","JPN":"あら王様、ぐっすり眠れた？","ENG":"Did you have a good nap, little majesty?","TWN":"國王，午睡睡得好嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"그레모리…?","JPN":"グレモリー……？","ENG":"Gremory...?","TWN":"葛茉莉…？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"취해서 헤롱헤롱대지 않고 먼저 말을 걸다니 별일이구나. 무슨 큰일이라도 있는 것이냐?","JPN":"酔いつぶれていないなんて、珍しいな。何かあったのか？","ENG":"How unusual of you to talk to me first without getting blackout drunk. Is something going on with you?","TWN":"竟然沒喝醉就先找我說話，真是稀奇。召喚本王是有什麼大事嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"가끔 생각이 많아지는 날은 너무 취하지 않는 편이 정리에 도움이 되거든.","JPN":"物思いにふける日は、酔わない方が考えをまとめやすいのよ。","ENG":"On days when there is a lot to think about, not getting too drunk helps me organize my thoughts.","TWN":"有時候想法太多的時候，不太醉反而有助於整理思緒。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"배고프도다.","JPN":"お腹が空いたぞ。","ENG":"I'm hungry.","TWN":"本王肚子餓。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"뭐가 먹고 싶은데?","JPN":"何が食べたい？","ENG":"What do you want to eat?","TWN":"國王想吃什麼呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"빵이 먹고 싶구나.","JPN":"パンが食べたい。","ENG":"I want bread.","TWN":"我想吃麵包。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머, 평소엔 사탕만 찾더니. 웬일로 빵을?","JPN":"あら、今日はキャンディーじゃないの？　パンなんて珍しいわね。","ENG":"Oh, you normally ask for candy. Why is it bread this time?","TWN":"喔？平時不都是喜歡糖果嗎，怎麼今天突然改性子想吃麵包啦？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"방금 꿈을 꿨는데, 엄청 달콤한 빵을 먹었노라.","JPN":"さっき夢の中で、とても甘いパンを食べたのだ。","ENG":"I had a dream that I was eating a super sweet piece of bread.","TWN":"剛剛我做了個夢，夢見吃了甜甜的麵包。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"흐음… 달콤한 빵이라…","JPN":"ふーん……甘いパンねえ……","ENG":"Hmm... sweet bread, you say...?","TWN":"嗯…甜甜的甜麵包嗎…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"생크림이 잔뜩 들어간 타르트였을까?","JPN":"生クリームたっぷりのタルトかしら？","ENG":"Was it a tart filled with whipped cream?","TWN":"是放了很多鮮奶油的水果塔嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"오오, 그것도 맛있겠구나!","JPN":"おお、それも美味しそうだな！","ENG":"Ooh! That also sounds tasty!","TWN":"哇喔，那也很好吃！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"그치만 꿈에서 먹은 빵은 그렇게 안 납작했다. 동글동글했노라.","JPN":"だが、夢の中のパンは平たくなかったぞ。丸いパンであった。","ENG":"But the bread in my dreams wasn't that flat. It was round.","TWN":"但夢裡的麵包不是扁的，是圓圓的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"혹시, 거기서 난 향기도 기억하니?","JPN":"そのパン、どんな匂いがしたか覚えてる？","ENG":"Do you happen to remember what it smelled like?","TWN":"你還記得那個香味嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"으음…!","JPN":"ううむ……！","ENG":"Um...!","TWN":"嗯…！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"그렇지! 포도 냄새가 잔뜩 났었노라!","JPN":"そうだ！　ブドウの香りがしたぞ！","ENG":"Right! It smelled like grapes!","TWN":"對了！有濃濃的葡萄香味！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그렇구나.","JPN":"そっか。","ENG":"I see.","TWN":"原來是這樣。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그럼 포도가 잔뜩 들어간 빵이겠네.","JPN":"じゃあ、ブドウがいっぱい入ったパンにしましょう。","ENG":"Then it must be a bread made with lots of grapes.","TWN":"那應該是放了很多葡萄乾的麵包吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"오늘은 가게 문 닫고 빵집이나 돌아다녀볼까?","JPN":"今日は店を閉めて、パン屋さんを巡りましょうか？","ENG":"Shall we close shop for today and go around the bakeries to find it?","TWN":"今天休息後去麵包店逛逛吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어쩌면, 그 꿈에서 본 거랑 비슷한 빵을 찾을지도 모르니까.","JPN":"夢で見たのと似たパンが見つかるかもしれないわ。","ENG":"Maybe we'll be able to find something similar to the one you saw in your dreams.","TWN":"說不定能找到和夢裡相似的麵包。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"오오, 그거 참 기특한 생각이로다!","JPN":"おお、素晴らしい提案だ！","ENG":"Ooh! What a brilliant idea!","TWN":"哇喔，這個主意真不錯！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"그런데, 출근한 하수인이 보이지 않는구나. 같이 가면 좋을 텐데.","JPN":"ところで、今日は下僕が見えないな。一緒に行けたらいいのだが。","ENG":"I don't see the subject who came into work today. It would've been nice for her to come with.","TWN":"不過，本王沒看到來上班的手下，她不一起去嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그 애는 오늘부로 관뒀어.","JPN":"あの子なら今日から来ないわよ。","ENG":"She quit today.","TWN":"她今天辭職了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"엑…!","JPN":"えっ……！","ENG":"Eck...?!","TWN":"蛤…！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"혹시 이 몸이 어제 스무디를 너무 많이 만들게 했다고 화내더냐?","JPN":"もしや、吾輩が昨日スムージーをたくさん作らせたせいで怒ったのか？","ENG":"Is it because she got angry that I made her make a lot of smoothies yesterday?","TWN":"難道說，是因為昨天叫她做太多冰沙，所以生氣啦？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"설마… 이 몸을 원망하면서 떠난 건 아니겠지?!","JPN":"まさか……吾輩を恨んで出て行ったのではないだろうな？","ENG":"She didn't... quit while resenting me, did she?!","TWN":"她不會…是生我的氣才離開的吧？！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그건 아닐 거야. 더 좋은 동네에 집을 구하게 돼서 떠나는 거라고 했거든.","JPN":"それは違うと思うわ。もっといいところに家を見つけたから、この街を出るんだって。","ENG":"I don't think so. She said she had to leave because she found a house in a better neighborhood.","TWN":"才不是呢。是因為找到更好的房子才離開的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L9_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"그, 그러냐?","JPN":"そ、そうか？","ENG":"D-did she now?","TWN":"是喔？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L10_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"음! 하수인에게 좋은 일이 생기다니, 나도 마음이 한결 놓이는구나.","JPN":"うむ！　下僕にいいことがあったのなら、吾輩も一安心だ。","ENG":"Mm! I feel relieved that something good has happened to my subject.","TWN":"嗯！只要手下過得好，本王就安心囉。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"그런데, 이 몸의 스무디는 이제 누가 만들어주는 것이냐?","JPN":"ところで、吾輩のスムージーは誰が作ってくれるのだ？","ENG":"But now... who will make me my smoothies?","TWN":"但是，現在誰來給本王做冰沙呢…？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L14_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"걱정마렴.","JPN":"心配しないで。","ENG":"Don't you worry about that.","TWN":"別擔心。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"다음 아이는… 머잖아 만날 것 같으니까.","JPN":"次の子は……もうすぐ出会えそうだから。","ENG":"We will soon... meet another child.","TWN":"下一個手下…很快就會來的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_IDLE"}}}}]`);export{e as default};